#include <bits/stdc++.h>
using namespace std;
int n;
struct node
{
    int s,e;
};
node a[1000005];
bool fun(node x,node y)
{
    return x.e<y.e;
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++) cin>>a[i].s>>a[i].e;
    sort(a+1,a+1+n,fun);
    int en=0,ans=0;
    for(int i=1;i<=n;i++)
    {
        if(a[i].s>=en) ans++,en=a[i].e;
    }
    cout<<ans;
    return 0;
}
